import React, { useState } from "react";
import Sidebar from "./components/Sidebar";
import LoginBox from "./components/LoginBox";
import { FaProjectDiagram } from "react-icons/fa";

const AppLayout = ({ children }) => {
  const [showLogin, setShowLogin] = useState(false);

  const toggleLogin = () => {
    setShowLogin(!showLogin);
  };

  return (
    <div className="flex h-screen">
      {/* Sidebar */}
      <aside className="w-64 bg-gray-900 text-white">
        <Sidebar />
      </aside>

      {/* Main Content */}
      <div className="flex-1 flex flex-col">
        {/* Header */}
        <header className="bg-gradient-to-r from-purple-700 to-indigo-800 text-white py-6 px-8 shadow-lg text-center">
          <FaProjectDiagram className="text-5xl text-yellow-300 mb-2" />
          <h1 className="text-2xl font-semibold tracking-wide">
            🚀 Manage Your Projects Efficiently With
          </h1>
          <h2 className="text-4xl font-extrabold text-yellow-300 mt-2">Proma</h2>
        </header>

        {/* Page Content */}
        <div className="p-6 relative">
          {/* Login Button */}
          <button
            onClick={toggleLogin}
            className="absolute top-4 right-4 bg-yellow-400 text-black px-4 py-2 rounded-lg font-semibold hover:bg-yellow-500 transition"
          >
            Login
          </button>

          {children}
        </div>
      </div>

      {/* Login Box Popup */}
      {showLogin && (
        <div className="fixed inset-0 flex items-center justify-center bg-black bg-opacity-50 z-50">
          <div className="bg-white p-6 rounded-lg shadow-xl relative w-96">
            <button
              onClick={toggleLogin}
              className="absolute top-2 right-2 text-gray-700 hover:text-gray-900"
            >
              ✖
            </button>
            <LoginBox />
          </div>
        </div>
      )}
    </div>
  );
};

export default AppLayout;
